cardCss:
/*
 * UKIYO-E WOODBLOCK
 * ─────────────────────────────────────────────────────────────────────────
 * Aesthetic : Hokusai / Hiroshige flat-colour woodblock print — bold
 *             outlines, discrete colour zones, cartouche title box
 * Fonts     : Noto Serif JP — classical Japanese print weight
 * Palette   : sky blue #87b8c8 · earth ochre #c8a050 · cream #f0e8d0
 *             ink dark #1a1008
 * Background: SVG feTurbulence (fractalNoise, baseFrequency 0.025) →
 *             feComponentTransfer discrete (3-4 bands) → woodblock colour zones
 *             feConvolveMatrix Sobel-style outline pass over colour regions
 * Cartouche : CSS rectangular border with inner rule (right-side panel)
 */

@import url("https://fonts.googleapis.com/css2?family=Noto+Serif+JP:wght@400;700;900&display=swap");

:root {
  --uw-sky:    #87b8c8;
  --uw-ochre:  #c8a050;
  --uw-cream:  #f0e8d0;
  --uw-ink:    #1a1008;
  --uw-earth:  #8a6030;
}

html, body, div#qa { height: 100%; }

.card { background: var(--uw-cream); min-height: 100%; }

.off-screen { position: absolute; left: -9999px; }

.uw-card {
  min-height: 100%;
  display: flex;
  flex-direction: column;
  position: relative;
  box-sizing: border-box;
}

/* ── FRONT ── */
.uw-front { background: var(--uw-sky); }

.uw-bg-layer {
  position: absolute;
  inset: 0;
  background: var(--uw-sky);
  filter: url(#uw-woodblock);
  pointer-events: none;
  z-index: 0;
  opacity: 0.9;
}

.uw-cartouche {
  position: relative;
  z-index: 1;
  align-self: flex-end;
  margin: 1.5rem 1.5rem 1.5rem auto;
  padding: 1rem 1.2rem;
  background: var(--uw-cream);
  border: 2px solid var(--uw-ink);
  box-shadow: inset 0 0 0 3px var(--uw-cream), inset 0 0 0 5px var(--uw-ink);
  max-width: 14rem;
  min-width: 10rem;
  text-align: center;
}

.uw-cartouche--back {
  align-self: flex-start;
  margin: 1.5rem auto 1.5rem 1.5rem;
}

.uw-cartouche-label {
  font-family: "Noto Serif JP", serif;
  font-size: 2.5rem;
  font-weight: 900;
  color: var(--uw-ink);
  margin: 0 0 0.5rem;
  line-height: 1;
}

.uw-prompt {
  font-family: "Noto Serif JP", serif;
  font-size: 1rem;
  color: var(--uw-ink);
  opacity: 0.7;
  margin: 0 0 0.8rem;
  line-height: 1.4;
}

.uw-input-wrap { width: 100%; }
.uw-input-wrap input {
  font-family: "Noto Serif JP", serif;
  font-size: 1rem;
  background: var(--uw-cream);
  border: 1px solid var(--uw-ink);
  color: var(--uw-ink);
  width: 100%;
  padding: 0.35rem 0.5rem;
  box-sizing: border-box;
}
.uw-input-wrap input:focus { outline: none; border-color: var(--uw-earth); }

.uw-hint-wrap { margin-top: 0.6rem; }
.uw-hint-link { font-family: "Noto Serif JP", serif; font-size: 0.8rem; color: var(--uw-earth); text-decoration: underline; }
.uw-hint-text { font-family: "Noto Serif JP", serif; font-size: 0.9rem; color: var(--uw-ink); margin-top: 0.3rem; }
.uw-audio { margin: 0 0 0.8rem; }

/* ── BACK ── */
.uw-back { background: var(--uw-cream); }

.uw-term {
  font-family: "Noto Serif JP", serif;
  font-size: 3rem;
  font-weight: 700;
  color: var(--uw-ink);
  margin: 0 0 0.4rem;
  line-height: 1.2;
}

.uw-reading    { font-family: "Noto Serif JP", serif; font-size: 1.5rem; color: var(--uw-earth); margin: 0 0 0.3rem; }
.uw-translation { font-family: "Noto Serif JP", serif; font-size: 1.3rem; color: var(--uw-ink); opacity: 0.8; margin: 0 0 0.2rem; }
.uw-transliteration { font-family: "Noto Serif JP", serif; font-size: 1.1rem; color: var(--uw-earth); opacity: 0.65; font-style: italic; margin: 0; }
.uw-tags { font-family: "Noto Serif JP", serif; font-size: 0.9rem; color: var(--uw-earth); opacity: 0.5; margin: 0.5rem 0 0; }

/* ── IMAGE ZONE ── */
.uw-image-zone {
  position: relative;
  z-index: 1;
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 1rem;
}

.uw-image-zone img {
  max-width: 100%;
  max-height: 16rem;
  object-fit: contain;
  filter: url(#uw-outline) saturate(0.7) contrast(1.1);
}

.append-play-btn-text a::after { content: "▶"; color: var(--uw-earth); }
.append-play-btn-text svg { display: none; }
.append-play-btn-text button { font-size: 2rem; cursor: pointer; }
